void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("VaanStraten_1");			link.l1 = StringFromKey("VaanStraten_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("VaanStraten_3");			link.l1 = StringFromKey("VaanStraten_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("VaanStraten_5");			link.l1 = StringFromKey("VaanStraten_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("VaanStraten_7");			link.l1 = StringFromKey("VaanStraten_8");			link.l1.go = "4";			link.l2 = StringFromKey("VaanStraten_9");			link.l2.go = "4a";		break;		case "4a":			dialog.text = StringFromKey("VaanStraten_10");			link.l1 = "...";			link.l1.go = "Exit";			AddDialogExitQuest("FL5_s24");		break;		case "4":			PlaceCharacter(CharacterFromID("JozephFushe"), "goto", "random_must_be_near");			LAi_SetActorType(CharacterFromID("JozephFushe"));			LAi_ActorFollow(CharacterFromID("JozephFushe"), pchar, "", -1);			dialog.text = StringFromKey("VaanStraten_11");			link.l1 = StringFromKey("VaanStraten_12");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("VaanStraten_13");			link.l1 = StringFromKey("VaanStraten_14");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("VaanStraten_15");			link.l1 = StringFromKey("VaanStraten_16");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("VaanStraten_17");			link.l1 = StringFromKey("VaanStraten_18");			link.l1.go = "8";		break;		case "8":			dialog.text = StringFromKey("VaanStraten_19");			link.l1 = "...";			link.l1.go = "exit";			AddDialogExitQuest("FL5a_s24");		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}